package fr.istic.taa.jaxrs.rest;

import fr.istic.taa.jaxrs.domain.Pet;
import io.swagger.v3.oas.annotations.Parameter;
import jakarta.ws.rs.Consumes;
import jakarta.ws.rs.GET;
import jakarta.ws.rs.POST;
import jakarta.ws.rs.Path;
import jakarta.ws.rs.PathParam;
import jakarta.ws.rs.QueryParam;
import jakarta.ws.rs.Produces;
import jakarta.ws.rs.core.Response;

@Path("pet")
@Produces({"application/json", "application/xml"})
public class PetResource {

	@GET
	@Path("/{petId}")
	public Pet getPetById(@PathParam("petId") Long petId) {
		// return pet by ID from path
		// TODO: Implémenter la récupération du pet depuis la base de données
		Pet pet = new Pet();
		pet.setId(petId);
		return pet;
	}

	@GET
	public Pet getPet(@QueryParam("petId") Long petId) {
		// return pet by ID from query parameter
		// TODO: Implémenter la récupération du pet depuis la base de données
		if (petId != null) {
			Pet pet = new Pet();
			pet.setId(petId);
			return pet;
		}
		return new Pet();
	}

	@POST
	@Consumes("application/json")
	public Response addPet(
			@Parameter(description = "Pet object that needs to be added to the store", required = true) Pet pet) {
		// TODO: Implémenter l'ajout du pet dans la base de données
		return Response.ok().entity("Pet ajouté avec succès").build();
	}
}

package fr.istic.taa.jaxrs.rest;

import fr.istic.taa.jaxrs.domain.Pet;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.ws.rs.Consumes;
import jakarta.ws.rs.GET;
import jakarta.ws.rs.POST;
import jakarta.ws.rs.Path;
import jakarta.ws.rs.PathParam;
import jakarta.ws.rs.QueryParam;
import jakarta.ws.rs.Produces;
import jakarta.ws.rs.core.Response;

@Path("pet")
@Produces({"application/json", "application/xml"})
@Tag(name = "Pets", description = "API pour gérer les animaux (Pets)")
public class PetResource {

	/**
	 * Récupère un animal par son ID (paramètre de chemin)
	 * 
	 * @param petId L'identifiant de l'animal
	 * @return L'animal ou une erreur
	 */
	@GET
	@Path("/{petId}")
	@Operation(
		summary = "Récupérer un pet par ID",
		description = "Retourne les détails d'un pet spécifique via le chemin"
	)
	@ApiResponse(responseCode = "200", description = "Pet trouvé",
		content = @Content(schema = @Schema(implementation = Pet.class)))
	public Response getPetById(
			@Parameter(description = "ID du pet", required = true, example = "1")
			@PathParam("petId") Long petId) {
		try {
			if (petId == null || petId <= 0) {
				return Response.status(Response.Status.BAD_REQUEST)
						.entity("{\"erreur\": \"ID invalide\"}")
						.build();
			}

			Pet pet = new Pet();
			pet.setId(petId);
			// TODO: Implémenter la récupération du pet depuis la base de données
			return Response.ok(pet).build();
		} catch (Exception e) {
			return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
					.entity("{\"erreur\": \"" + e.getMessage() + "\"}")
					.build();
		}
	}

	/**
	 * Récupère un animal par ID optionnel (paramètre de requête)
	 * 
	 * @param petId L'identifiant optionnel de l'animal
	 * @return L'animal trouvé ou un pet vide
	 */
	@GET
	@Operation(
		summary = "Récupérer un pet",
		description = "Retourne un pet via paramètre de requête (optionnel)"
	)
	@ApiResponse(responseCode = "200", description = "Pet retourné")
	public Response getPet(
			@Parameter(description = "ID optionnel du pet", example = "1")
			@QueryParam("petId") Long petId) {
		try {
			Pet pet = new Pet();

			if (petId != null && petId > 0) {
				pet.setId(petId);
				// TODO: Implémenter la récupération du pet depuis la base de données
			}

			return Response.ok(pet).build();
		} catch (Exception e) {
			return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
					.entity("{\"erreur\": \"" + e.getMessage() + "\"}")
					.build();
		}
	}

	/**
	 * Ajoute un nouvel animal
	 * 
	 * @param pet L'animal à ajouter
	 * @return Message de succès ou erreur
	 */
	@POST
	@Consumes("application/json")
	@Operation(
		summary = "Ajouter un nouveau pet",
		description = "Crée et ajoute un nouvel animal dans le système"
	)
	@ApiResponse(responseCode = "200", description = "Pet ajouté avec succès")
	public Response addPet(
			@Parameter(description = "Objet Pet à ajouter", required = true)
			Pet pet) {
		try {
			if (pet == null) {
				return Response.status(Response.Status.BAD_REQUEST)
						.entity("{\"erreur\": \"Pet ne peut pas être null\"}")
						.build();
			}

			// TODO: Implémenter l'ajout du pet dans la base de données

			return Response.ok()
					.entity("{\"message\": \"Pet ajouté avec succès\", \"id\": " + pet.getId() + "}")
					.build();
		} catch (Exception e) {
			return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
					.entity("{\"erreur\": \"" + e.getMessage() + "\"}")
					.build();
		}
	}
}
